// IaaS — declare the VM, disk, NIC, NSG, VNet explicitly
resource vm 'Microsoft.Compute/virtualMachines@2024-03-01' = {
  name: 'vm-orders'
  location: resourceGroup().location
  properties: {
    hardwareProfile: { vmSize: 'Standard_D2s_v5' }
    storageProfile: {
      imageReference: {
        publisher: 'Canonical'
        offer: '0001-com-ubuntu-server-jammy'
        sku: '22_04-lts-gen2'
        version: 'latest'
      }
      osDisk: { createOption: 'FromImage', managedDisk: { storageAccountType: 'Premium_LRS' } }
    }
    osProfile: {
      computerName: 'vm-orders'
      adminUsername: 'azureuser'
      // ssh key or password here
    }
    networkProfile: {
      networkInterfaces: [{ id: nic.id }]
    }
  }
}

// PaaS — declare the App Service Plan + Web App; OS/runtime managed by Azure
resource plan 'Microsoft.Web/serverfarms@2023-12-01' = {
  name: 'plan-orders'
  location: resourceGroup().location
  sku: { name: 'P1v3', tier: 'PremiumV3' }
  kind: 'linux'
  properties: { reserved: true }
}

resource webApp 'Microsoft.Web/sites@2023-12-01' = {
  name: 'orders-api'
  location: resourceGroup().location
  properties: {
    serverFarmId: plan.id
    siteConfig: { linuxFxVersion: 'PYTHON|3.11' }
  }
}

// Serverless — declare a Function App on Consumption plan
resource funcApp 'Microsoft.Web/sites@2023-12-01' = {
  name: 'func-orders'
  location: resourceGroup().location
  kind: 'functionapp,linux'
  properties: {
    serverFarmId: consumptionPlan.id
    siteConfig: { linuxFxVersion: 'PYTHON|3.11' }
  }
}
